function fb(a, b) { if (a) { return a; } return b; }
var resp = fb($.steps.fetchEmails.response, {});
var messages = fb(resp.messages, []);
var replyTone = fb($.input.replyTone, 'professional and friendly');

var emailData = '';
messages.forEach(function(msg, i) {
  var headers = msg.payload ? (fb(msg.payload.headers, [])) : [];
  var subject = '';
  var from = '';
  var date = '';
  headers.forEach(function(h) {
    if (h.name === 'Subject') subject = h.value;
    if (h.name === 'From') from = h.value;
    if (h.name === 'Date') date = h.value;
  });
  var snippet = fb(msg.snippet, '');
  emailData += '--- Email ' + (i + 1) + ' ---\n';
  emailData += 'From: ' + from + '\n';
  emailData += 'Subject: ' + subject + '\n';
  emailData += 'Date: ' + date + '\n';
  emailData += 'Preview: ' + snippet.slice(0, 500) + '\n\n';
});

return { emailData: emailData, emailCount: messages.length, replyTone: replyTone };

var data = $.steps.compileEmails.output;

var prompt = 'You are an email assistant. For each email below, draft a reply that is ' + data.replyTone + '. Also provide a summary and priority assessment.\n\n';
prompt += 'EMAILS TO PROCESS (' + data.emailCount + '):\n\n';
prompt += data.emailData + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Draft a concise, appropriate reply for each email\n';
prompt += '- Assess priority: urgent, normal, or low\n';
prompt += '- Summarize each email in one sentence\n';
prompt += '- Flag any emails that should NOT get an auto-reply (e.g. newsletters, no-reply)\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "summary": "overview of the email batch",\n';
prompt += '  "emails": [\n';
prompt += '    {\n';
prompt += '      "from": "sender",\n';
prompt += '      "subject": "subject line",\n';
prompt += '      "oneSentenceSummary": "what this email is about",\n';
prompt += '      "priority": "urgent/normal/low",\n';
prompt += '      "shouldReply": true,\n';
prompt += '      "draftReply": "the drafted reply text",\n';
prompt += '      "replyNotes": "any notes about the reply"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "urgentCount": 0,\n';
prompt += '  "skipCount": 0\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiDraft.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, emails: [], urgentCount: 0 }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':email: Email Drafts for Review', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fb(ai.summary, 'Email drafts ready for review.') } });

var urgentCount = fb(ai.urgentCount, 0);
var skipCount = fb(ai.skipCount, 0);
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':rotating_light: *Urgent:* ' + urgentCount + '  |  :fast_forward: *Auto-skip:* ' + skipCount + '  |  *Total:* ' + (fb(ai.emails, [])).length }] });
blocks.push({ type: 'divider' });

var emails = fb(ai.emails, []);
emails.forEach(function(email) {
  var priorityIcon = ':white_circle:';
  if (email.priority === 'urgent') priorityIcon = ':red_circle:';
  if (email.priority === 'normal') priorityIcon = ':large_blue_circle:';

  var emailText = priorityIcon + ' *' + (fb(email.subject, 'No Subject')) + '*\n';
  emailText += '_From:_ ' + (fb(email.from, 'Unknown')) + '\n';
  emailText += '_Summary:_ ' + (fb(email.oneSentenceSummary, '')) + '\n';

  if (email.shouldReply) {
    emailText += '\n*Draft Reply:*\n> ' + (fb(email.draftReply, '')).replace(/\n/g, '\n> ') + '\n';
    if (email.replyNotes) emailText += '\n_Note:_ ' + email.replyNotes;
  } else {
    emailText += '\n_:no_entry_sign: Recommended: Do not reply_';
    if (email.replyNotes) emailText += ' — ' + email.replyNotes;
  }

  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: emailText } });
  blocks.push({ type: 'divider' });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':point_up: Review and approve before sending | Powered by Gmail + Claude AI + One CLI' }] });

var fallback = 'Email Drafts: ' + (fb(ai.emails, [])).length + ' replies drafted for review';
return { blocks: blocks, fallback: fallback };
